sql:
SELECT product_id, search_query
FROM product_positions
WHERE search_query = 'gaming mouse';

SELECT sentiment
FROM reviews
WHERE review_id = '1' AND product_id = '1';

external_knowledge:
- "Shining stars" refers to the top-rated reviews with high sentiment scores; 
- "Marked with a red flag" refers to reviews that have been flagged for suspicion of fraud (is_flagged = 1); 
- "Middle-of-the-road" refers to neutral reviews (sentiment = 0); 
- "Put to the test" refers to the total number of reviews for each product (total_reviews > 100); 
- "Emotional impact" refers to the sentiment score of the reviews; 
- "Level of admiration" refers to the rating given by the reviewer; 
- "Freshness" refers to the review date.

sql:
SELECT review_id
FROM reviews
WHERE review_id = '1';

SELECT COUNT(review_id) AS review_count
FROM product_reviews
WHERE product_id = '0';
